type Tab = "home" | "games" | "tools" | "mine";
type PunishmentSource = "undercover" | "catbomb" | "miss" | "likely";
const DEFAULT_PLAYERS = ["小明", "小红", "阿杰", "圆圆"];

function useStored<T>(key:string, initial:T) {
  const [value,setValue]=useState(initial),[hydrated,setHydrated]=useState(false);
  useEffect(()=>{try{const saved=localStorage.getItem(key);if(saved)setValue(JSON.parse(saved))}catch{}setHydrated(true)},[key]);
  useEffect(()=>{if(hydrated)localStorage.setItem(key,JSON.stringify(value))},[key,value,hydrated]);
  return [value,setValue] as const;
}
function parseQuestionLines(text:string){const seen=new Set<string>();return text.split(/\r?\n/).map(x=>x.trim()).filter(Boolean).filter(line=>{const key=line.toLowerCase();if(seen.has(key))return false;seen.add(key);return true}).slice(0,500)}

type CatVariant="gamepad"|"cards"|"party"|"support"|"heart"|"box"|"flag"|"sleep"|"search";
function CatIcon({variant,className=""}:{variant:CatVariant;className?:string}){
  const base=process.env.NEXT_PUBLIC_BASE_PATH||"";
  return <span className={`cat-sprite ${className}`} style={{backgroundImage:`url(${base}/icons/ui/${variant}.png)`}} role="img" aria-label="猫咪派对图标"/>;
}
function Cat({mood="happy",className=""}:{mood?:"happy"|"wink"|"party"|"sleep";className?:string}) {
  const variants:Record<NonNullable<typeof mood>,CatVariant>={happy:"heart",wink:"cards",party:"party",sleep:"sleep"};
  return <CatIcon variant={variants[mood]} className={`cat-doodle ${className}`}/>;
}
const GAME_ICON_IDS=["charades","undercover","turtle","garden","seven","never","story","dontdo","drawguess","telephone","likely","forehead","king","miss","oldmaid","bluff","truth","werewolf","bomb","catbomb","randomchallenge"];
function GameCatIcon({game,className=""}:{game:Game;className?:string}){
  const base=process.env.NEXT_PUBLIC_BASE_PATH||"",id=game.id==="catbomb"?"randomchallenge":GAME_ICON_IDS.includes(game.id)?game.id:"charades";
  return <span className={`game-icon-sprite ${className}`} style={{backgroundImage:`url(${base}/icons/games/${id}.png)`}} role="img" aria-label={`${game.name}猫咪图标`}/>;
}
const gameTime=(game:Game)=>game.durationLabel||String(game.minutes);
const COMPLETED_GAME_IDS=new Set(["charades","seven","miss","garden","undercover","catbomb","truth","never","likely","dontdo"]);
const isGameComplete=(game:Game)=>COMPLETED_GAME_IDS.has(game.id);
const NOTICE_READ_KEY="party_notice_read_20260708_toolbox_v2";
const ADULT_CONTENT_KEY="party_adult_content_enabled_v1";

export default function App(){
  const[tab,setTab]=useState<Tab>("home"),[detail,setDetail]=useState<Game|null>(null),[play,setPlay]=useState<Game|null>(null),[tool,setTool]=useState<string|null>(null),[punishmentPlayers,setPunishmentPlayers]=useState<string[]>([]),[punishmentSource,setPunishmentSource]=useState<PunishmentSource|null>(null);
  const[utility,setUtility]=useState<"notice"|"settings"|null>(null);const[pawHintDismissed,setPawHintDismissed]=useStored("party_paw_hint_dismissed",false);const[noticeRead,setNoticeRead]=useState<boolean|null>(null);
  const[players,setPlayers]=useStored("party_players",DEFAULT_PLAYERS);const[favorites,setFavorites]=useStored<string[]>("party_favorites",[]);const[recent,setRecent]=useStored<string[]>("party_recent",[]);const[level,setLevel]=useStored<Level>("party_level","轻松");const[adultContentEnabled,setAdultContentEnabled]=useStored(ADULT_CONTENT_KEY,false);
  useEffect(()=>{try{setNoticeRead(localStorage.getItem(NOTICE_READ_KEY)==="true")}catch{setNoticeRead(false)}},[]);
  useEffect(()=>{if(!("serviceWorker"in navigator))return;if(process.env.NODE_ENV==="production"){navigator.serviceWorker.register(`${process.env.NEXT_PUBLIC_BASE_PATH||""}/sw.js`).catch(()=>{})}else{navigator.serviceWorker.getRegistrations().then(items=>items.forEach(item=>item.unregister()));if("caches"in window)caches.keys().then(keys=>Promise.all(keys.map(key=>caches.delete(key))))}},[]);
  const openNotice=()=>{setUtility("notice");setNoticeRead(true);try{localStorage.setItem(NOTICE_READ_KEY,"true")}catch{}};
  const open=(g:Game)=>{setDetail(g);setRecent(r=>[g.id,...r.filter(x=>x!==g.id)].slice(0,8))};const start=(g:Game)=>{setDetail(null);setPunishmentPlayers([]);setPlay(g);setRecent(r=>[g.id,...r.filter(x=>x!==g.id)].slice(0,8))};
  return <main><div className="ambient a1"/><div className="ambient a2"/><div className="paw-pattern"/><div className="app-shell">
    <header className="topbar"><button className="brand" onClick={()=>setTab("home")}><img className="brand-party-cat" src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/ui/party.png`} alt="派对小猫"/><span>猫咪派对<small>和好朋友，喵一晚</small></span></button><div className="header-tools"><button className={`header-cat-action${noticeRead===false?" has-update":""}`} onClick={openNotice} aria-label={noticeRead===false?"打开公告栏，有新通知":"打开公告栏"}><img src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/header/notice.png`} alt=""/></button><button className="header-cat-action" onClick={()=>setUtility("settings")} aria-label="打开设置"><img src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/header/settings.png`} alt=""/></button><div className="paw-entry"><button className="avatar cat-avatar" onClick={()=>{setTab("mine");setPawHintDismissed(true)}} aria-label="设置所有玩家">ฅ</button>{!pawHintDismissed&&<div className="paw-hint"><button onClick={()=>setPawHintDismissed(true)} aria-label="关闭提示"><X/></button><b>玩家从这里集合喵</b><span>点猫爪可统一设置所有游戏的玩家人数</span></div>}</div></div></header>
    {tab==="home"&&<HomePage onTab={setTab} open={open} start={start} recent={recent}/>} {tab==="games"&&<GamesPage open={open}/>} {tab==="tools"&&<ToolsPage players={players} onTool={setTool}/>} {tab==="mine"&&<MinePage players={players} setPlayers={setPlayers} favorites={favorites} recent={recent} level={level} setLevel={setLevel} open={open}/>}
  </div>{!detail&&!play&&!tool&&!utility&&<nav className="bottom-nav cat-nav"><Nav active={tab==="home"} icon={<Home/>} label="首页" onClick={()=>setTab("home")}/><Nav active={tab==="games"} icon={<Search/>} label="找游戏" onClick={()=>setTab("games")}/><Nav active={tab==="tools"} icon={<Dices/>} label="百宝箱" onClick={()=>setTab("tools")}/><Nav active={tab==="mine"} icon={<UserRound/>} label="我的" onClick={()=>setTab("mine")}/></nav>}
    {utility==="notice"&&<NoticeBoard onClose={()=>setUtility(null)}/>} {utility==="settings"&&<SettingsPanel playerCount={players.length} adultContentEnabled={adultContentEnabled} setAdultContentEnabled={setAdultContentEnabled} onPlayers={()=>{setUtility(null);setTab("mine")}} onClose={()=>setUtility(null)}/>}
    {detail&&<Detail game={detail} favorite={favorites.includes(detail.id)} onFav={()=>setFavorites(f=>f.includes(detail.id)?f.filter(x=>x!==detail.id):[...f,detail.id])} onClose={()=>setDetail(null)} onStart={()=>start(detail)}/>} {play&&<Play game={play} players={players} setPlayers={setPlayers} level={level} adultContentEnabled={adultContentEnabled} punishmentPlayers={punishmentPlayers} punishmentSource={punishmentSource} onClose={()=>setPlay(null)} onSwitch={(id,names=[],source=null)=>{setPunishmentPlayers(names);setPunishmentSource(source);setPlay(games.find(g=>g.id===id)||null)}} onReturnSource={()=>{setPunishmentPlayers([]);setPlay(games.find(g=>g.id===punishmentSource)||null)}}/>} {tool&&<Tool type={tool} players={players} onClose={()=>setTool(null)}/>} </main>
}
function Nav({active,icon,label,onClick}:{active:boolean;icon:React.ReactNode;label:string;onClick:()=>void}){return <button className={active?"active":""} onClick={onClick}>{icon}<span>{label}</span></button>}

function NoticeBoard({onClose}:{onClose:()=>void}){return <div className="overlay utility-overlay" onMouseDown={e=>e.target===e.currentTarget&&onClose()}><section className="utility-card"><button className="close" onClick={onClose}><X/></button><img className="utility-cat" src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/header/notice.png`} alt="通知猫咪"/><span className="utility-kicker">猫咪公告栏</span><h2>最近更新</h2><div className="notice-list"><article><time>7 月 8 日 · 最新</time><b>百宝箱更新了幸运转盘和随机工具</b><p>幸运转盘改成纯自定义选项，添加后就能生成转盘；随机点名支持玩家、奖励、惩罚分别自定义；随机分组也能在全局玩家外临时加人。</p></article><article><time>7 月 8 日</time><b>加入了不要做挑战，更新了小姐牌规则</b><p>不要做挑战加入半手动秘密任务、多人手机视角、记录板和自定义任务池；小姐牌补充了国王游戏、15 20、三字经、炸弹牌和全场老大的具体规则。</p></article><article><time>7 月 8 日</time><b>更新了谁最可能、小姐牌和我有你没有</b><p>谁最可能加入线下投票与轮流匿名投票；小姐牌增加更多玩法，优化规则与使用体验；我有你没有规则更完整，并在小姐牌中加入了工具箱。</p></article><article><time>目前进度</time><b>已完成优化的游戏</b><p>你比划我来猜、逢七过、小姐牌、逛三园、谁是卧底、猫咪炸弹、真心话大冒险、我有你没有、谁最可能、不要做挑战。</p></article></div></section></div>}
function SettingsPanel({playerCount,adultContentEnabled,setAdultContentEnabled,onPlayers,onClose}:{playerCount:number;adultContentEnabled:boolean;setAdultContentEnabled:Dispatch<SetStateAction<boolean>>;onPlayers:()=>void;onClose:()=>void}){return <div className="overlay utility-overlay" onMouseDown={e=>e.target===e.currentTarget&&onClose()}><section className="utility-card"><button className="close" onClick={onClose}><X/></button><img className="utility-cat" src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/header/settings.png`} alt="设置猫咪"/><span className="utility-kicker">猫咪设置</span><h2>设置</h2><div className="settings-list"><button onClick={onPlayers}><span className="setting-symbol">ฅ</span><span><b>所有玩家</b><small>当前 {playerCount} 人 · 全部游戏和工具共用</small></span><ChevronRight/></button><label className="settings-toggle"><span className="setting-symbol">🔞</span><span><b>显示成人内容</b><small>开启后显示 18 禁、18+、亲密/身体接触类题库；请确认所有参与者均已成年并自愿参与。</small></span><input type="checkbox" checked={adultContentEnabled} onChange={e=>setAdultContentEnabled(e.target.checked)}/><i/></label><a href="mailto:2240706994@qq.com?subject=猫咪派对反馈"><span className="setting-symbol">✉</span><span><b>联系开发者</b><small>建议、问题和新玩法都欢迎来信</small></span><ChevronRight/></a></div><p className="settings-email">2240706994@qq.com</p></section></div>}

function HomePage({onTab,open,start,recent}:{onTab:(t:Tab)=>void;open:(g:Game)=>void;start:(g:Game)=>void;recent:string[]}){
  const[pick,setPick]=useState<Game|null>(null);const featured=games.find(g=>g.id==="miss")!;const quick=games.filter(g=>["charades","undercover","truth","catbomb"].includes(g.id));const completedGames=games.filter(isGameComplete);const random=()=>setPick(completedGames[Math.floor(Math.random()*completedGames.length)]);
  return <div className="page home-page"><section className="hero cat-hero"><div className="hero-copy"><span className="eyebrow"><Sparkles/>猫猫今晚玩什么？</span><h1>朋友到齐，<br/><em>快乐开喵！</em></h1><p>一台手机，装下整场聚会的好玩点子。</p><div className="hero-actions"><button className="primary" onClick={()=>onTab("games")}><Search/>找个游戏</button><button className="secondary" onClick={random}><Shuffle/>猫猫帮选</button></div></div><div className="hero-art cat-stage"><span className="doodle-sun">☀</span><span className="doodle-fish">𓆝</span><span className="doodle-star">✦</span><Cat mood="party"/></div></section>
    <section><div className="section-head"><div><span className="eyebrow warm"><Zap/>马上开喵</span><h2>经典不冷场</h2></div><button onClick={()=>onTab("games")}>全部游戏 <ChevronRight/></button></div><div className="quick-grid">{quick.map(g=><GameCard key={g.id} game={g} onClick={()=>open(g)}/>)}</div></section>
    <section className="featured cat-featured"><div className="featured-icon"><img className="featured-game-icon" src={`${process.env.NEXT_PUBLIC_BASE_PATH||""}/icons/games/miss.png`} alt="小姐牌"/><span>猫猫推荐</span></div><div><span className="meta">{featured.min}–{featured.max} 人 · {gameTime(featured)} 分钟</span><h2>{featured.name}</h2><p>{featured.tagline}</p><button onClick={()=>start(featured)}>直接开局 <ChevronRight/></button></div></section>
    {recent.length>0&&<section><div className="section-head"><div><span className="eyebrow"><History/>最近玩过</span><h2>再来一局喵</h2></div></div><div className="row-scroll">{recent.slice(0,4).map(id=>{const g=games.find(x=>x.id===id)!;return <MiniCard key={id} game={g} onClick={()=>open(g)}/>})}</div></section>}
    <section className="tool-teaser cat-teaser"><div><span>🐾 猫咪百宝箱</span><h2>抽签、分组、计时<br/>小事交给猫猫</h2><button onClick={()=>onTab("tools")}>打开百宝箱 <ChevronRight/></button></div><Cat mood="happy"/></section>
    {pick&&<div className="overlay"><div className="pick-dialog cat-dialog"><button className="close" onClick={()=>setPick(null)}><X/></button><Cat mood="wink"/><small>猫猫替你选好了</small><h2>{pick.name}</h2><p>{pick.tagline}</p><div className="tag-row"><span>{pick.min}–{pick.max} 人</span><span>{gameTime(pick)} 分钟</span></div><button className="primary full" onClick={()=>{setPick(null);open(pick)}}>就玩这个喵</button><button className="text-btn" onClick={random}><RotateCcw/>再选一次</button></div></div>}
  </div>
}
function GameCard({game,onClick}:{game:Game;onClick:()=>void}){const complete=isGameComplete(game);return <button className={`game-card ${game.color}${complete?"":" pending"}`} onClick={onClick}><span className="card-ears"/><GameCatIcon game={game} className="game-cat-icon"/><span className="level-pill">{complete?game.level:"待开发"}</span><h3>{game.name}</h3><p>{game.tagline}</p><div><span><Users/>{game.min}–{game.max}</span><span><Clock3/>{gameTime(game)}′</span></div></button>}
function MiniCard({game,onClick}:{game:Game;onClick:()=>void}){return <button className="mini-card" onClick={onClick}><span className={`mini-icon ${game.color}`}><GameCatIcon game={game} className="mini-game-icon"/></span><span><b>{game.name}</b><small>{game.min}–{game.max} 人 · {gameTime(game)} 分钟</small></span><ChevronRight/></button>}

function GamesPage({open}:{open:(g:Game)=>void}){const[search,setSearch]=useState(""),[people,setPeople]=useState(0),[duration,setDuration]=useState(0),[req,setReq]=useState("全部"),[cat,setCat]=useState("全部");const filtered=useMemo(()=>games.filter(g=>(!search||g.name.includes(search)||g.tagline.includes(search))&&(!people||g.min<=people&&g.max>=people)&&(!duration||g.minutes<=duration)&&(req==="全部"||g.requirements.includes(req))&&(cat==="全部"||g.category===cat)).sort((a,b)=>Number(isGameComplete(b))-Number(isGameComplete(a))),[search,people,duration,req,cat]);return <div className="page games-page"><Title eyebrow="猫猫游戏单" title="找个对味的" text="看看现场有几只猫，马上匹配合适玩法。"/><div className="search"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="搜索游戏名称…"/></div><div className="filters"><Filter label="人数" values={["不限","4人","6人","8人","10人+"]} active={people?people>=10?"10人+":`${people}人`:"不限"} set={v=>setPeople(v==="不限"?0:parseInt(v))}/><Filter label="时长" values={["不限","15分钟","20分钟","30分钟"]} active={duration?`${duration}分钟`:"不限"} set={v=>setDuration(v==="不限"?0:parseInt(v))}/><Filter label="道具" values={["全部","无需道具","手机","纸笔","扑克牌"]} active={req} set={setReq}/><Filter label="类型" values={["全部","无道具","纸笔类","扑克牌","手机辅助"]} active={cat} set={setCat}/></div><div className="results-head"><b>找到 {filtered.length} 个游戏</b><button onClick={()=>{setPeople(0);setDuration(0);setReq("全部");setCat("全部")}}><RotateCcw/>重置</button></div><div className="catalog">{filtered.map(g=><GameCard key={g.id} game={g} onClick={()=>open(g)}/>)}</div>{!filtered.length&&<div className="empty"><Cat mood="sleep"/><h3>猫猫也没找到</h3><p>放宽一点条件试试看吧。</p></div>}</div>}
function Title({eyebrow,title,text}:{eyebrow:string;title:string;text:string}){return <div className="page-title"><span className="eyebrow"><Sparkles/>{eyebrow}</span><h1>{title}</h1><p>{text}</p></div>}
function Filter({label,values,active,set}:{label:string;values:string[];active:string;set:(v:string)=>void}){return <div className="filter-row"><b>{label}</b><div>{values.map(v=><button key={v} className={active===v?"on":""} onClick={()=>set(v)}>{v}</button>)}</div></div>}

const toolDefs=[{id:"blindbox",name:"小猫盲盒",desc:"全站共用的道具卡",emoji:"🎁",color:"pink"},{id:"wheel",name:"幸运转盘",desc:"自己加入选项生成转盘",emoji:"🎡",color:"coral"},{id:"pick",name:"随机点名",desc:"玩家、奖励、惩罚都能自定义",emoji:"☝️",color:"blue"},{id:"teams",name:"随机分组",desc:"全局玩家也能临时加人",emoji:"👥",color:"green"},{id:"timer",name:"聚会计时器",desc:"倒计时滴答滴答",emoji:"⏱️",color:"teal"}];
function ToolCatIcon({id}:{id:string}){const base=process.env.NEXT_PUBLIC_BASE_PATH||"";return <span className="tool-icon-sprite" style={{backgroundImage:`url(${base}/icons/tools/${id}.png)`}} role="img" aria-label="百宝箱猫咪图标"/>}
function ToolsPage({players,onTool}:{players:string[];onTool:(s:string)=>void}){return <div className="page tools-page"><Title eyebrow="猫咪百宝箱" title="小工具，大快乐" text="不用下载，伸出猫爪点开就能用。"/><div className="player-status cat-status"><Cat mood="wink"/><div><b>本场玩家 · {players.length} 人</b><small>{players.join("、")||"还没有添加玩家"}</small></div></div><div className="tool-grid">{toolDefs.map(t=><button key={t.id} className={`tool-card ${t.color}`} onClick={()=>onTool(t.id)}><ToolCatIcon id={t.id}/><div><h3>{t.name}</h3><p>{t.desc}</p></div><ChevronRight/></button>)}</div><div className="safety-note"><Heart/><div><b>快乐有边界</b><p>所有惩罚都可以跳过或重抽，猫猫不勉强任何人。</p></div></div></div>}

function MinePage({players,setPlayers,favorites,recent,level,setLevel,open}:{players:string[];setPlayers:React.Dispatch<React.SetStateAction<string[]>>;favorites:string[];recent:string[];level:Level;setLevel:(l:Level)=>void;open:(g:Game)=>void}){const[name,setName]=useState("");const add=()=>{const n=name.trim();if(n&&!players.includes(n)){setPlayers(p=>[...p,n]);setName("")}};return <div className="page mine-page"><Title eyebrow="我的猫窝" title="人齐了，就开喵" text="名单和偏好只保存在你的设备上。"/><section className="panel"><div className="panel-head"><div><Users/><span><b>玩家名单</b><small>所有游戏与工具共用</small></span></div><strong>{players.length} 人</strong></div><div className="chips">{players.map((p,i)=><span key={`${p}${i}`}>{p}<button onClick={()=>setPlayers(x=>x.filter((_,j)=>j!==i))}><X/></button></span>)}</div><div className="add-player"><input value={name} onChange={e=>setName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()} placeholder="输入玩家昵称"/><button onClick={add}><Plus/>添加</button></div></section><section className="panel"><div className="panel-head"><div><Settings2/><span><b>内容等级</b><small>题目和惩罚默认等级</small></span></div></div><div className="level-options">{(["轻松","熟人","刺激"]as Level[]).map(l=><button key={l} className={level===l?"on":""} onClick={()=>setLevel(l)}><span>{l==="轻松"?"🌿":l==="熟人"?"✨":"🔥"}</span><b>{l}</b><small>{l==="轻松"?"软乎乎":l==="熟人"?"更懂彼此":"大胆一点"}</small>{level===l&&<Check/>}</button>)}</div></section><ListSection title="我的收藏" icon={<Bookmark/>} ids={favorites} empty="喜欢的游戏会住在这里。" open={open}/><ListSection title="最近玩过" icon={<History/>} ids={recent} empty="还没有游戏脚印喵。" open={open}/><p className="privacy">🐾 无账号 · 无上传 · 数据仅存本机</p></div>}
function ListSection({title,icon,ids,empty,open}:{title:string;icon:React.ReactNode;ids:string[];empty:string;open:(g:Game)=>void}){return <section className="panel game-list"><div className="panel-head"><div>{icon}<span><b>{title}</b></span></div></div>{ids.length?ids.map(id=>{const g=games.find(x=>x.id===id);return g&&<MiniCard key={id} game={g} onClick={()=>open(g)}/>}):<p className="small-empty">{empty}</p>}</section>}

function Detail({game,favorite,onFav,onClose,onStart}:{game:Game;favorite:boolean;onFav:()=>void;onClose:()=>void;onStart:()=>void}){return <div className="sheet-overlay"><article className="detail-sheet"><div className={`detail-hero ${game.color}`}><div className="sheet-actions"><button onClick={onClose}><ArrowLeft/></button><button className={favorite?"fav on":"fav"} onClick={onFav}><Bookmark fill={favorite?"currentColor":"none"}/></button></div><GameCatIcon game={game} className="detail-cat-icon"/><span className="category">{game.category}</span><h1>{game.name}</h1><p>{game.tagline}</p><div className="detail-meta"><span><Users/>{game.min}–{game.max} 人</span><span><Clock3/>{gameTime(game)} 分钟</span><span><Zap/>{game.difficulty}</span></div></div><div className="detail-body"><section><h3>需要准备</h3><div className="requirement-row">{game.requirements.map(x=><span key={x}>🐾 {x}</span>)}</div></section><section><h3>怎么玩</h3><ol>{game.rules.map((r,i)=><li key={r}><span>{i+1}</span><p>{r}</p></li>)}</ol></section><section className="example"><b>举个例子</b><p>{game.example}</p></section><section><h3>胜利条件</h3><p>{game.victory}</p></section>{game.tip&&<section className="tip"><span>🐱</span><div><b>猫猫小贴士</b><p>{game.tip}</p></div></section>}</div><div className="sticky-action"><button className="primary full" onClick={onStart}>{game.tool?"马上开喵":"开始游戏"}<ChevronRight/></button></div></article></div>}

function Play({game,players,setPlayers,level,adultContentEnabled,punishmentPlayers,punishmentSource,onClose,onSwitch,onReturnSource}:{game:Game;players:string[];setPlayers:React.Dispatch<React.SetStateAction<string[]>>;level:Level;adultContentEnabled:boolean;punishmentPlayers:string[];punishmentSource:PunishmentSource|null;onClose:()=>void;onSwitch:(id:string,names?:string[],source?:PunishmentSource|null)=>void;onReturnSource:()=>void}){if(game.id==="charades")return <Charades adultContentEnabled={adultContentEnabled} onClose={onClose}/>;if(game.id==="garden")return <GardenGame onClose={onClose}/>;if(game.id==="seven")return <SevenGame onClose={onClose}/>;if(game.id==="never")return <NeverHaveIEverRules onClose={onClose}/>;if(game.id==="dontdo")return <DontDoGame players={players} setPlayers={setPlayers} onClose={onClose}/>;if(game.id==="miss")return <MissCardRules players={players} adultContentEnabled={adultContentEnabled} onClose={onClose}/>;if(game.id==="likely")return <LikelyGame initialPlayers={players} onClose={onClose} onTruthOrDare={names=>onSwitch("truth",names,"likely")}/>;if(game.id==="truth")return <TruthOrDare players={players} adultContentEnabled={adultContentEnabled} punishmentPlayers={punishmentPlayers} punishmentSource={punishmentSource} onClose={onClose} onReturnSource={onReturnSource}/>;if(game.id==="undercover")return <Undercover initialPlayers={players} adultContentEnabled={adultContentEnabled} onClose={onClose} onTruthOrDare={names=>onSwitch("truth",names,"undercover")}/>;if(game.id==="catbomb")return <CatBomb initialPlayers={players} onClose={onClose} onTruthOrDare={name=>onSwitch("truth",[name],"catbomb")}/>;if(game.tool==="identity")return <Identity game={game} players={players} onClose={onClose}/>;if(game.tool==="timer")return <TimerTool title={game.name} onClose={onClose}/>;return <Prompt game={game} players={players} level={level} onClose={onClose}/>}

type NeverGuideMode="自由模式"|"随机分类"|"灵感提示";
type NeverCategory={id:string;icon:string;name:string;desc:string;prompts:string[]};
const NEVER_MODE_GUIDES:{mode:NeverGuideMode;icon:string;title:string;desc:string}[]=[
  {mode:"自由模式",icon:"✨",title:"自由模式",desc:"不限制分类，玩家直接说真实经历，适合熟人和自然聊天。"},
  {mode:"随机分类",icon:"🎲",title:"随机分类",desc:"每轮抽一个方向，大家围绕主题发挥，适合防止冷场。"},
  {mode:"灵感提示",icon:"💡",title:"灵感提示",desc:"给分类和示例句，想不出题目时直接参考，适合新朋友破冰。"}
];
const NEVER_CATEGORIES:NeverCategory[]=[
  {id:"travel",icon:"🌍",name:"地方旅行",desc:"国家、城市、景点，以及路上的小经历。",prompts:["我有一个人旅行过。","我有去过海边看日出。","我有在外地迷路过。","我有坐过很久的火车。","我有临时改过旅行计划。","我有住过青旅或民宿。"]},
  {id:"skills",icon:"🎓",name:"技能学习",desc:"语言、乐器、运动、生活技能都可以。",prompts:["我会游泳。","我有学过一种乐器。","我有学过一门外语。","我有考过一个证书。","我有学过滑雪或滑冰。","我有自己修好过一个东西。"]},
  {id:"pets",icon:"🐱",name:"宠物动物",desc:"养过、接触过、害怕过的小动物。",prompts:["我有养过宠物。","我有被动物追过。","我有喂过流浪动物。","我有去过猫咖或宠物店。","我有怕过某种小动物。","我有给动物起过名字。"]},
  {id:"food",icon:"🍔",name:"美食饮品",desc:"吃过、喝过、做过、挑战过的味道。",prompts:["我有吃过很辣的东西。","我有自己做过一顿饭。","我有排队超过一小时吃东西。","我有点外卖点错过。","我有吃过榴莲。","我有喝过自己调的饮料。"]},
  {id:"games",icon:"🎮",name:"游戏爱好",desc:"游戏、桌游、收藏和长期兴趣。",prompts:["我有通宵玩过游戏。","我有玩过桌游。","我有为了爱好买过装备。","我有收藏过卡片或周边。","我有在游戏里认识朋友。","我有认真练过一个兴趣。"]},
  {id:"entertainment",icon:"🎬",name:"影视娱乐",desc:"电影、演唱会、综艺、音乐和追星。",prompts:["我有去过演唱会。","我有为一部电影哭过。","我有追完一整部剧。","我有喜欢过一个明星很久。","我有唱 K 唱到嗓子哑。","我有看过午夜场电影。"]},
  {id:"traffic",icon:"🚗",name:"交通体验",desc:"开车、坐船、飞行、堵车和迷路。",prompts:["我有驾照。","我有坐过船。","我有错过车或飞机。","我有坐反方向过。","我有骑车摔过。","我有在路上堵到怀疑人生。"]},
  {id:"achievement",icon:"🏆",name:"成就挑战",desc:"比赛、考试、公开表现和小小胜利。",prompts:["我有上台表演过。","我有参加过比赛。","我有拿过奖状或奖杯。","我有完成过一次长跑。","我有公开演讲过。","我有坚持打卡超过一个月。"]},
  {id:"collection",icon:"🎁",name:"物品收藏",desc:"买过、收藏过、弄丢过、舍不得扔的东西。",prompts:["我有收藏过票根。","我有买过盲盒。","我有一件舍不得扔的旧东西。","我有弄丢过很重要的东西。","我有买过同款不同颜色。","我有为了纪念买过小物件。"]},
  {id:"awkward",icon:"🤭",name:"尴尬经历",desc:"社死、误会、迟到、说错话，轻一点就好。",prompts:["我有叫错过别人的名字。","我有发错过消息。","我有迟到超过半小时。","我有认错过人。","我有在安静场合突然笑出来。","我有把秘密说漏嘴过。"]}
];
const NEVER_FREE_PROMPTS=["我有一个大家可能想不到的小经历。","我有一个最近才发现的习惯。","我有一件小时候做过的事。","我有一次很幸运的经历。","我有一个坚持过一段时间的爱好。","我有一件说出来会想笑的小糗事。"];
const NEVER_RULES=["每人建议竖起 5 根手指，也可以约定 3 根或 10 根。","轮流说一句真实的“我有……”，一次只说一件事情。","没有这件事的人收回一根手指；有的人保持不动。","手指全部收回后，可以分享一个相关故事、回答轻松问题、做小挑战，或继续旁观。","题目要让别人有可能拥有；不要故意说过于具体、过于私人或明显没人会有的内容。"];
function randomNeverIndex(length:number,current:number){if(length<=1)return 0;let next=current;while(next===current)next=Math.floor(Math.random()*length);return next}
function NeverHaveIEverRules({onClose}:{onClose:()=>void}){
  const[stage,setStage]=useState<"setup"|"playing">("setup"),[guide,setGuide]=useState<NeverGuideMode>("灵感提示"),[catIndex,setCatIndex]=useState(0),[promptIndex,setPromptIndex]=useState(0),[rulesOpen,setRulesOpen]=useState(false),[confirmExit,setConfirmExit]=useState(false);
  const category=NEVER_CATEGORIES[catIndex],pool=guide==="自由模式"?NEVER_FREE_PROMPTS:category.prompts,prompt=pool[promptIndex%pool.length];
  const chooseGuide=(value:NeverGuideMode)=>{setGuide(value);setPromptIndex(0)};
  const shuffleCategory=()=>{if(guide==="自由模式")setGuide("随机分类");setCatIndex(i=>randomNeverIndex(NEVER_CATEGORIES.length,i));setPromptIndex(0)};
  const shufflePrompt=()=>setPromptIndex(i=>randomNeverIndex(pool.length,i));
  const start=()=>{setPromptIndex(0);setStage("playing")};
  return <div className={`fullscreen never-screen ${stage==="playing"?"is-playing":""}`}><Head onClose={()=>setConfirmExit(true)} title="🖐️ 我有你没有"/><div className="never-shell">
    <header className="never-hero"><GameCatIcon game={games.find(g=>g.id==="never")!} className="never-hero-icon"/><div><span>破冰规则辅助</span><h1>五根手指，交换真实经历</h1><p>手机只给规则和灵感；谁先说、怎么轮流、谁收手指，都由现场自己决定。</p></div></header>
    {stage==="setup"?<><section className="never-finger-note"><b>手指数自由约定</b><p>开始前大家自行决定竖几根手指就好。想快一点可以 3 根，最常见是 5 根，想聊久一点可以 10 根。</p></section><section className="never-setup"><div className="never-section-head"><div><span>分类玩法</span><h2>要不要给一点方向？</h2></div></div><div className="never-segments">{(["自由模式","随机分类","灵感提示"] as NeverGuideMode[]).map(value=><button key={value} className={guide===value?"on":""} onClick={()=>chooseGuide(value)}>{value}</button>)}</div></section><section className="never-mode-guide">{NEVER_MODE_GUIDES.map(item=><article key={item.mode} className={guide===item.mode?"active":""}><span>{item.icon}</span><div><b>{item.title}</b><p>{item.desc}</p></div>{guide===item.mode&&<Check/>}</article>)}</section><div className="never-actions setup"><button className="primary" onClick={start}><Sparkles/>开始游戏</button></div></>:<><section className="never-game-status"><div><b>{guide}</b><span>分类玩法</span></div></section><section className="never-win-condition"><b>胜利条件</b><p>一直轮流说“我有...”，直到只剩一个玩家，则为胜利者。</p></section><section className={`never-card ${guide==="自由模式"?"free":""}`}><div className="never-card-top"><span>{guide==="自由模式"?"✨":category.icon}</span><div><small>{guide}</small><h2>{guide==="自由模式"?"自由发挥":category.name}</h2></div></div><p>{guide==="自由模式"?"不限制分类，玩家直接说一句真实的“我有……”。":category.desc}</p>{guide==="灵感提示"&&<div className="never-prompt"><b>可以这样说</b><strong>{prompt}</strong></div>}{guide==="随机分类"&&<div className="never-prompt muted"><b>本轮方向</b><strong>围绕“{category.name}”说一句我有。</strong></div>}{guide==="自由模式"&&<div className="never-prompt muted"><b>灵感方向</b><strong>{prompt}</strong></div>}</section><div className="never-actions playing"><button className="secondary" onClick={shuffleCategory}><Shuffle/>{guide==="自由模式"?"抽分类":"换分类"}</button><button className="secondary" onClick={shufflePrompt}><RotateCcw/>换一句提示</button><button className="secondary wide" onClick={()=>setRulesOpen(true)}><Sparkles/>查看具体规则（详细版）</button><button className="primary wide" onClick={()=>setStage("setup")}><Settings2/>重设规则</button></div></>}
  </div>{rulesOpen&&<NeverRulesModal onClose={()=>setRulesOpen(false)}/>} {confirmExit&&<div className="exit-confirm" role="dialog" aria-modal="true" aria-labelledby="never-exit-title"><div className="exit-confirm-card"><GameCatIcon game={games.find(g=>g.id==="never")!} className="never-exit-icon"/><h2 id="never-exit-title">要退出我有你没有吗？</h2><p>当前规则选择不会保存，本局会结束。</p><div><button className="secondary" onClick={()=>setConfirmExit(false)}>继续游戏</button><button className="exit-danger" onClick={onClose}>确认退出</button></div></div></div>}</div>
}
function NeverRulesModal({onClose}:{onClose:()=>void}){return <div className="miss-modal never-modal" onMouseDown={e=>e.target===e.currentTarget&&onClose()}><section className="miss-sheet detail never-sheet"><button className="close" onClick={onClose}><X/></button><GameCatIcon game={games.find(g=>g.id==="never")!} className="never-modal-icon"/><span className="miss-detail-kicker">规则说明</span><h2>我有你没有</h2><p>重点是破冰和聊天，不是把别人难倒。</p><article><ol className="never-rule-list">{NEVER_RULES.map((rule,i)=><li key={rule}><span>{i+1}</span><p>{rule}</p></li>)}</ol></article><div className="miss-example"><b>好题目</b><span>我有养过宠物。我有一个人旅行过。我有学过乐器。我有上台表演过。</span></div><div className="never-bad-example"><b>不推荐</b><span>我有昨天吃过某家餐厅的 3 号套餐。这类题太具体，容易让游戏失去聊天感。</span></div><div className="never-drink-note">熟人酒局也可以把归零惩罚改成自愿喝一口，或换成无酒精饮品、真心话、大冒险。</div><div className="miss-actions"><button className="primary" onClick={onClose}><Check/>知道了</button></div></section></div>}
