function RuleChoiceDetail({rank,rule,selected,kind,players,onBack,onClose,onUse}:{rank:MissRank;rule:MissRule;selected:boolean;kind:"main"|"heart";players:string[];onBack:()=>void;onClose:()=>void;onUse:()=>void}){return <div className="miss-modal"><section className="miss-sheet detail"><button className="close" onClick={onClose}><X/></button><MissCardIcon id={rank} className="miss-rank-badge"/><span className="miss-detail-kicker">{kind==="heart"?"红心特殊规则":"规则详情"}</span><h2>{rule.name}</h2><p>{rule.short}</p><article>{rule.details}</article><div className="miss-example"><b>例子</b><span>{rule.example}</span></div>{rule.helper==="seven"&&<NumberPassMiniChecker base={7}/>} {rule.helper==="six"&&<NumberPassMiniChecker base={6}/>} {rule.helper==="garden"&&<GardenMiniPicker/>}{rule.helper==="never"&&<MissNeverMiniTool/>}{rule.helper==="likely"&&<MissLikelyMiniTool players={players}/>}<div className="miss-actions"><button className="secondary" onClick={onBack}>返回选择</button><button className="primary" onClick={onUse}>{selected?<><Check/>已使用</>:<><Check/>使用这个规则</>}</button></div></section></div>}
function CustomRuleModal({onClose,onSave}:{onClose:()=>void;onSave:(data:{name:string;short:string;details:string;example:string})=>void}){const[name,setName]=useState(""),[short,setShort]=useState(""),[details,setDetails]=useState(""),[example,setExample]=useState("");return <div className="miss-modal"><section className="miss-sheet custom"><button className="close" onClick={onClose}><X/></button><h2>自定义规则</h2><label><span>规则名</span><input value={name} onChange={e=>setName(e.target.value)} placeholder="例如：双倍 K"/></label><label><span>短说明</span><input value={short} onChange={e=>setShort(e.target.value)} placeholder="显示在总览牌面上"/></label><label><span>详细规则</span><textarea value={details} onChange={e=>setDetails(e.target.value)} placeholder="写清楚抽到后怎么执行"/></label><label><span>例子</span><textarea value={example} onChange={e=>setExample(e.target.value)} placeholder="举一个现场例子"/></label><button className="primary full" onClick={()=>onSave({name,short,details,example})}>保存并使用</button></section></div>}
