 const remove=(id:string)=>{setBanks(list=>list.filter(bank=>bank.id!==id));if(openBank===id)setOpenBank("")};
 const importLines=(bank:TDCustomBank,kind:"truthQuestions"|"dareQuestions",file?:File|null)=>{if(!file)return;const reader=new FileReader();reader.onload=()=>{const lines=parseQuestionLines(String(reader.result||""));patch(bank.id,{[kind]:parseQuestionLines([...bank[kind],...lines].join("\n"))} as Partial<TDCustomBank>)};reader.readAsText(file)};
